{
  "name": "@procertus-docs/procertus-categorization",
  "version": "0.0.1",
  "private": true,
  "type": "module",
  "sideEffects": false,
  "main": "./src/index.ts",
  "module": "./src/index.ts",
  "types": "./src/index.ts",
  "exports": {
    ".": {
      "types": "./src/index.ts",
      "import": "./src/index.ts",
      "default": "./src/index.ts"
    }
  },
  "scripts": {
    "build": "tsc",
    "lint": "eslint ."
  },
  "peerDependencies": {
    "react": "^18.0.0 || ^19.0.0"
  },
  "devDependencies": {
    "@types/react": "^19.2.13",
    "@workspace/eslint-config": "workspace:*",
    "@workspace/typescript-config": "workspace:*",
    "bun-types": "latest",
    "typescript": "^5.8.2"
  }
}

{
  "extends": "@workspace/typescript-config/react-library.json",
  "compilerOptions": {
    "baseUrl": ".",
    "resolveJsonModule": true
  },
  "include": ["src/**/*.ts", "src/**/*.tsx", "src/**/*.json"],
  "exclude": ["node_modules", "dist"]
}

/**
 * Procertus process / product categorization: types aligned to
 * `src/data/procertus-categorization.json` in this package (see {@link ProcertusCategorizationDoc}).
 */

export type Certification = {
  ce: string;
  benor: string;
  atg: string;
  ssdInnovationAttest: string;
};

export type Procedures = {
  procertus: string;
  partijkeuring: string;
  epd: string;
};

export type TreeNodeKind = 'group' | 'product';

export type TreeNode = {
  id: string;
  kind: TreeNodeKind;
  label: string;
  productTypeStreamLabel?: string;
  children?: TreeNode[];
  certification?: Certification;
  procedures?: Procedures;
};

export type ProcertusSpreadsheetSource = {
  readonly spreadsheetExport: {
    fileName: string;
    sheetName?: string;
    exportedAt?: string;
    notes?: string;
  };
};

export type WizardEntryPoint =
  | 'regulated-certificate'
  | 'atg-attest'
  | 'innovation-attest-ssd'
  | (string & {});

export type ProcertusCategorizationMeta = {
  schemaVersion: string;
  treeVersion: string;
  canonicalLocale: string;
  source: ProcertusSpreadsheetSource;
  wizard?: { entryPoints?: readonly WizardEntryPoint[] };
};

export type ProcertusCategorizationDoc = {
  meta: ProcertusCategorizationMeta;
  clusters: readonly TreeNode[];
};

export type CertificationLabelKey = 'ce' | 'benor' | 'atg' | 'ssd';

export type FlatProductEntry = {
  path: string[];
  node: TreeNode;
};

export type CertifiableRow = {
  id: string;
  pathStr: string;
  label: string;
  value: string;
};

import type { CertificationLabelKey } from './types';

export const CERTIFICATION_LABEL_ORDER: readonly CertificationLabelKey[] = [
  'ce',
  'benor',
  'atg',
  'ssd',
] as const;

export const CERTIFICATION_LABEL_META: Readonly<
  Record<CertificationLabelKey, { short: string; description: string }>
> = {
  ce: { short: 'CE', description: 'CE marking' },
  benor: { short: 'BENOR', description: 'BENOR' },
  atg: { short: 'ATG', description: 'ATG (attest)' },
  ssd: { short: 'SSD', description: 'Innovation attest (SSD)' },
} as const;

/**
 * Default categorization document shipped with this package: `src/data/procertus-categorization.json`.
 * Regenerate from the DecisionTree CSV:
 * `bun run apps/frontend-docs/scripts/build-procertus-categorization.ts`
 * (CSV input: `apps/frontend-docs/src/analysis/data/DecisionTree_v2.xlsx - Overzicht_v2.csv`.)
 * Copy / sync date for downstream mirrors: 2026-04-24 (ISO); see `meta.source` in the JSON.
 */
import type { ProcertusCategorizationDoc } from './types';
import procertusCategorizationJson from './data/procertus-categorization.json';

export const defaultProcertusCategorizationDoc: ProcertusCategorizationDoc =
  procertusCategorizationJson as ProcertusCategorizationDoc;

import type {
  CertifiableRow,
  Certification,
  CertificationLabelKey,
  FlatProductEntry,
  Procedures,
  ProcertusCategorizationDoc,
  TreeNode,
} from './types';

export function getEntryPoints(doc: ProcertusCategorizationDoc): readonly string[] {
  return doc.meta.wizard?.entryPoints?.length ? [...doc.meta.wizard.entryPoints] : [];
}

/** Depth-first: every node id → node (mutates the given map). */
function walkNodes(nodes: readonly TreeNode[], out: Map<string, TreeNode>): void {
  for (const n of nodes) {
    out.set(n.id, n);
    if (n.children?.length) {
      walkNodes(n.children, out);
    }
  }
}

export function buildNodeByIdMap(clusters: readonly TreeNode[]): ReadonlyMap<string, TreeNode> {
  const m = new Map<string, TreeNode>();
  walkNodes(clusters, m);
  return m;
}

function findNodeInTree(nodes: readonly TreeNode[], id: string): TreeNode | undefined {
  for (const n of nodes) {
    if (n.id === id) {
      return n;
    }
    if (n.children?.length) {
      const f = findNodeInTree(n.children, id);
      if (f) {
        return f;
      }
    }
  }
  return undefined;
}

export function findNodeById(doc: ProcertusCategorizationDoc, id: string): TreeNode | undefined {
  return findNodeInTree(doc.clusters, id);
}

export function collectGroupIds(nodes: readonly TreeNode[]): string[] {
  return nodes.flatMap(n => {
    if (n.kind === 'group' && n.children?.length) {
      return [n.id, ...collectGroupIds(n.children)];
    }
    return [];
  });
}

export function flattenProducts(
  nodes: readonly TreeNode[],
  pathPrefix: string[]
): FlatProductEntry[] {
  return nodes.flatMap(n => {
    const path = [...pathPrefix, n.label];
    if (n.kind === 'product') {
      return [{ path, node: n }];
    }
    if (n.children?.length) {
      return flattenProducts(n.children, path);
    }
    return [];
  });
}

export function getCertValue(cert: Certification, key: CertificationLabelKey): string {
  switch (key) {
    case 'ce':
      return cert.ce;
    case 'benor':
      return cert.benor;
    case 'atg':
      return cert.atg;
    case 'ssd':
      return cert.ssdInnovationAttest;
  }
}

/** True when a chip should be shown: non-empty and not `/` or `-` (per symbol notes in UI). */
export function hasCertifiableChip(value: string): boolean {
  const v = value.trim();
  if (!v || v === '/' || v === '-') {
    return false;
  }
  return true;
}

export function statusTextWhenNoChip(value: string): string {
  const v = value.trim();
  if (v === '') {
    return 'Momenteel niet aangeboden';
  }
  if (v === '/') {
    return 'Certificatie niet mogelijk';
  }
  if (v === '-') {
    return 'Certificatie niet door ons';
  }
  return v;
}

export function chipVariant(value: string): 'default' | 'secondary' {
  return value.trim() === '(x)' ? 'secondary' : 'default';
}

export function chipDisplay(short: string, value: string): string {
  const v = value.trim();
  if (v === 'x') {
    return short;
  }
  if (v === '(x)') {
    return `${short} · later / federatie`;
  }
  return `${short} · ${v}`;
}

export function hasAnyProcedureData(p: Procedures): boolean {
  return (
    p.procertus.trim().length > 0 || p.partijkeuring.trim().length > 0 || p.epd.trim().length > 0
  );
}

export function productMatchesCertLabel(node: TreeNode, selected: CertificationLabelKey): boolean {
  if (node.kind !== 'product' || !node.certification) {
    return false;
  }
  const v = getCertValue(node.certification, selected);
  return hasCertifiableChip(v);
}

/** Shallow-clone groups with pruned `children` — only branches with certifiable products. */
export function filterClustersByCertLabel(
  nodes: readonly TreeNode[],
  selected: CertificationLabelKey
): TreeNode[] {
  return nodes.reduce<TreeNode[]>((acc, node) => {
    if (node.kind === 'product') {
      if (productMatchesCertLabel(node, selected)) {
        acc.push(node);
      }
      return acc;
    }
    if (node.kind === 'group' && node.children?.length) {
      const nextChildren = filterClustersByCertLabel(node.children, selected);
      if (nextChildren.length > 0) {
        acc.push({ ...node, children: nextChildren });
      }
    }
    return acc;
  }, []);
}

export function getCertifiableRowsForLabel(
  flatProducts: readonly FlatProductEntry[],
  selected: CertificationLabelKey
): CertifiableRow[] {
  return flatProducts
    .map(({ path, node }) => {
      if (node.kind !== 'product' || !node.certification) {
        return null;
      }
      const v = getCertValue(node.certification, selected);
      if (!hasCertifiableChip(v)) {
        return null;
      }
      const pathStr = path.slice(0, -1).join(' › ');
      return { id: node.id, pathStr, label: node.label, value: v };
    })
    .filter((r): r is CertifiableRow => r !== null);
}

import { createContext, type ReactNode, useContext, useMemo } from 'react';
import { defaultProcertusCategorizationDoc } from './categorization-data';
import { buildNodeByIdMap, collectGroupIds, flattenProducts } from './helpers';
import type { FlatProductEntry, ProcertusCategorizationDoc, TreeNode } from './types';

export type ProcertusCategorizationValue = {
  /** Full document (meta + clusters). */
  doc: ProcertusCategorizationDoc;
  /** All nodes (group + product) for O(1) lookup. */
  nodeById: ReadonlyMap<string, TreeNode>;
  /** Product leaves with full label path from the cluster roots. */
  flatProducts: readonly FlatProductEntry[];
  /** `group` node ids, depth-first, for expand/collapse helpers. */
  groupIds: readonly string[];
};

const ProcertusCategorizationContext = createContext<ProcertusCategorizationValue | null>(null);

function useBuildValue(doc: ProcertusCategorizationDoc): ProcertusCategorizationValue {
  return useMemo(() => {
    const flatProducts = flattenProducts(doc.clusters, []);
    return {
      doc,
      nodeById: buildNodeByIdMap(doc.clusters),
      flatProducts,
      groupIds: collectGroupIds(doc.clusters),
    };
  }, [doc]);
}

export type ProcertusCategorizationProviderProps = {
  children: ReactNode;
  /** Optional override (e.g. tests or a future CMS-backed snapshot). */
  doc?: ProcertusCategorizationDoc;
};

export function ProcertusCategorizationProvider({
  children,
  doc: docProp,
}: ProcertusCategorizationProviderProps) {
  const doc = docProp ?? defaultProcertusCategorizationDoc;
  const value = useBuildValue(doc);
  return (
    <ProcertusCategorizationContext.Provider value={value}>
      {children}
    </ProcertusCategorizationContext.Provider>
  );
}

export function useProcertusCategorization(): ProcertusCategorizationValue {
  const ctx = useContext(ProcertusCategorizationContext);
  if (ctx == null) {
    throw new Error(
      'useProcertusCategorization must be used within ProcertusCategorizationProvider'
    );
  }
  return ctx;
}

import { useMemo } from 'react';
import { filterClustersByCertLabel, getCertifiableRowsForLabel, getEntryPoints } from './helpers';
import { useProcertusCategorization } from './ProcertusCategorizationContext';
import type { CertificationLabelKey, TreeNode } from './types';

export function useProcertusCategorizationDoc() {
  return useProcertusCategorization().doc;
}

export function useProcertusCategorizationMeta() {
  return useProcertusCategorization().doc.meta;
}

/** Wizard entry point ids (e.g. `regulated-certificate`). */
export function useProcertusEntryPoints() {
  const { doc } = useProcertusCategorization();
  return useMemo(() => getEntryPoints(doc), [doc]);
}

export function useProcertusClusters() {
  return useProcertusCategorization().doc.clusters;
}

export function useProcertusFlatProducts() {
  return useProcertusCategorization().flatProducts;
}

export function useProcertusGroupIds() {
  return useProcertusCategorization().groupIds;
}

/** O(1) by id; `undefined` if `nodeId` is empty or not found. */
export function useProcertusNodeById(nodeId: string | undefined): TreeNode | undefined {
  const { nodeById } = useProcertusCategorization();
  return useMemo(() => {
    if (nodeId == null || nodeId === '') {
      return undefined;
    }
    return nodeById.get(nodeId);
  }, [nodeById, nodeId]);
}

export function useCertifiableRowsForLabel(selected: CertificationLabelKey) {
  const { flatProducts } = useProcertusCategorization();
  return useMemo(
    () => getCertifiableRowsForLabel(flatProducts, selected),
    [flatProducts, selected]
  );
}

export function useFilteredClustersByCertLabel(selected: CertificationLabelKey) {
  const { doc } = useProcertusCategorization();
  return useMemo(() => filterClustersByCertLabel(doc.clusters, selected), [doc.clusters, selected]);
}

