import { Tick01Icon } from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";
import { cn, iconStroke } from "@procertus-ui/ui";
import {
  Stepper,
  StepperIndicator,
  StepperItem,
  StepperNav,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@procertus-ui/ui";
import type { ReactNode } from "react";
import { useMemo } from "react";

export type OnboardingStepperStep = {
  id: string;
  title: string;
  description?: string;
};

export type OnboardingStepperProps = {
  className?: string;
  /**
   * Stepper orientation. Horizontal fits `OnboardingFlowShell` above the H1; vertical
   * suits a narrow side rail beside the main step body.
   */
  orientation?: "horizontal" | "vertical";
  /**
   * Steps in order. The ReUI / primitive step index is **1-based**; this component maps
   * to and from the **0-based** `activeStep` used by `useOnboardingFlowShell`.
   */
  steps: OnboardingStepperStep[];
  /**
   * Current step index, **0-based** (same as `useOnboardingFlowShell` → `activeStep`).
   */
  activeStep: number;
  /**
   * Called with the new **0-based** index when the user moves focus by activating a
   * step. Omit to make the nav display-only (still works with a controlled `activeStep` from a parent).
   */
  onStepChange?: (index: number) => void;
  /**
   * If false, step triggers do not call `onStepChange` and are inert. Use for progress-only UI.
   */
  interactive?: boolean;
};

const completedIcon = (size: number) => (
  <HugeiconsIcon
    icon={Tick01Icon}
    className="text-primary"
    style={iconStroke(size * 0.4)}
  />
);

export function OnboardingStepper({
  className,
  steps,
  activeStep,
  onStepChange,
  orientation = "horizontal",
  interactive = true,
}: OnboardingStepperProps) {
  const value1 = useMemo(
    () => Math.min(steps.length, Math.max(1, activeStep + 1)),
    [activeStep, steps.length]
  );

  if (steps.length === 0) {
    return null;
  }

  return (
    <Stepper
      className={cn(orientation === "vertical" && "w-full max-w-[14rem] sm:max-w-none", className)}
      value={value1}
      onValueChange={
        onStepChange && interactive
          ? (v) => onStepChange(v - 1)
          : undefined
      }
      defaultValue={value1}
      orientation={orientation}
      indicators={{
        completed: completedIcon(8),
        loading: undefined,
      }}
    >
      <StepperNav
        className={cn(
          "gap-0",
          orientation === "horizontal" && "items-start",
          orientation === "vertical" && "items-stretch"
        )}
      >
        {steps.map((s, i) => {
          const n = i + 1;
          return (
            <OnboardingStepperItem
              key={s.id}
              n={n}
              step={s}
              interactive={interactive}
              isLast={i === steps.length - 1}
              orientation={orientation}
            />
          );
        })}
      </StepperNav>
    </Stepper>
  );
}

type ItemProps = {
  n: number;
  step: OnboardingStepperStep;
  interactive: boolean;
  isLast: boolean;
  orientation: "horizontal" | "vertical";
};

function OnboardingStepperItem({ n, step, interactive, isLast, orientation }: ItemProps) {
  return (
    <StepperItem step={n} disabled={!interactive}>
      <div
        className={cn(
          "flex min-w-0",
          orientation === "horizontal" ? "flex-1 items-start gap-2" : "w-full items-start gap-2"
        )}
      >
        <StepperTrigger
          className={cn(
            "max-w-full min-w-0",
            !interactive && "pointer-events-none cursor-default opacity-100",
            orientation === "vertical" && "w-full"
          )}
        >
          <StepperIndicator>{n}</StepperIndicator>
          <div className="min-w-0 flex-1 text-start group-data-[orientation=vertical]/stepper-nav:pb-0">
            <StepperTitle className="line-clamp-2">{step.title}</StepperTitle>
            {step.description ? (
              <p className="mt-0.5 line-clamp-2 text-xs leading-[1.5] text-muted-foreground">
