/**
 * Single **selectable** option in a `RadioGroup`: one value per group. Use
 * `emphasis` to separate primary paths (product certification) from secondary
 * (ATG) and tertiary (innovation / SSD) entry points, per the certification
 * request flow analysis.
 */
import { cva, type VariantProps } from "class-variance-authority";
import type { ReactNode } from "react";

import { cn } from "@/lib/utils";
import {
  Field,
  FieldContent,
  FieldDescription,
  FieldLabel,
  FieldTitle,
  Label,
  RadioGroupItem,
} from "@procertus-ui/ui";

const fieldLabelEmphasis = cva(
  [
    "w-full has-[>[data-slot=field]]:rounded-lg has-[>[data-slot=field]]:border has-[>[data-slot=field]]:transition-[box-shadow,background-color,border-color,opacity,transform] *:data-[slot=field]:p-2.5",
  ],
  {
    variants: {
      emphasis: {
        primary: [
          "has-[>[data-slot=field]]:border-2 has-[>[data-slot=field]]:border-border has-[>[data-slot=field]]:shadow-proc-xs has-data-checked:has-[>[data-slot=field]]:border-primary/40 has-data-checked:has-[>[data-slot=field]]:bg-primary/5 has-data-checked:has-[>[data-slot=field]]:shadow-proc-tactile dark:has-data-checked:has-[>[data-slot=field]]:bg-primary/10",
        ],
        secondary: [
          "has-[>[data-slot=field]]:border-border/80 has-[>[data-slot=field]]:bg-card has-data-checked:has-[>[data-slot=field]]:border-primary/30 has-data-checked:has-[>[data-slot=field]]:bg-muted/40",
        ],
        tertiary: [
          "has-[>[data-slot=field]]:border-dashed has-[>[data-slot=field]]:border-muted-foreground/30 has-[>[data-slot=field]]:bg-muted/10 has-data-[slot=field]:p-2 has-data-checked:has-[>[data-slot=field]]:border-primary/25 has-data-checked:has-[>[data-slot=field]]:bg-muted/25",
        ],
      },
    },
    defaultVariants: { emphasis: "primary" },
  },
);

const titleEmphasis = cva("", {
  variants: {
    emphasis: {
      primary: "text-base",
      secondary: "text-sm",
      tertiary: "text-sm font-medium text-muted-foreground",
    },
  },
  defaultVariants: { emphasis: "primary" },
});

const descEmphasis = cva("", {
  variants: {
    emphasis: {
      primary: "text-sm",
      secondary: "text-sm",
      tertiary: "text-xs",
    },
  },
  defaultVariants: { emphasis: "primary" },
});

export type SelectChoiceEmphasis = NonNullable<VariantProps<typeof fieldLabelEmphasis>["emphasis"]>;

export type SelectChoiceCardProps = {
  className?: string;
  /**
   * Must match a `RadioGroupItem` value; parent supplies `RadioGroup` with the same
   * value domain (single choice).
   */
  value: string;
  /**
   * Stable `id` for the radio and label; unique within the page.
   */
  radioId: string;
  title: ReactNode;
  description?: ReactNode;
  /** e.g. icon in a start column beside title/description. */
  leading?: ReactNode;
  /**
   * Visual and structural weight. **Primary** — main product path. **Secondary** — strong
   * but alternate (e.g. ATG). **Tertiary** — de-emphasized (e.g. innovation attest / SSD).
   * @default "primary"
   */
  emphasis?: SelectChoiceEmphasis;
  disabled?: boolean;
};

export function SelectChoiceCard({
  className,
  value,
  radioId,
  title,
  description,
  leading,
  emphasis = "primary",
  disabled = false,
}: SelectChoiceCardProps) {
  return (
    <FieldLabel
      className={cn("group/choice select-none", fieldLabelEmphasis({ emphasis }), className)}
    >
      <Field
        data-choice-emphasis={emphasis}
        orientation="horizontal"
        className="items-stretch *:data-[slot=field-content]:min-w-0 not-has-[>_[data-slot=field-content]_[data-slot=field]]:items-center"
        data-disabled={disabled}
      >
        <RadioGroupItem
          value={value}
          id={radioId}
          disabled={disabled}
          className="mt-1.5"
          aria-disabled={disabled}
        />
        <FieldContent
          className={cn(leading && "min-w-0", leading && "flex flex-row items-start gap-3")}
        >
          {leading ? <div className="shrink-0 self-start pt-0.5 text-muted-foreground [&_svg]:size-5">{leading}</div> : null}
          <div className="min-w-0 flex-1">
            <FieldTitle className={titleEmphasis({ emphasis })}>
              <Label
                htmlFor={radioId}
                className={cn(emphasis === "tertiary" && "text-muted-foreground", "text-left leading-snug font-medium")}
              >
                {title}
              </Label>
            </FieldTitle>
            {description ? (
              <FieldDescription
                className={cn("mt-1.5", descEmphasis({ emphasis }))}
              >
                {description}
              </FieldDescription>
            ) : null}
          </div>
        </FieldContent>
      </Field>
    </FieldLabel>
  );
}

import type { ComponentProps } from "react";

import { cn } from "@/lib/utils";
import { FieldSet, FieldLegend, RadioGroup } from "@procertus-ui/ui";

export type SelectChoiceCardGroupProps = ComponentProps<typeof RadioGroup> & {
  className?: string;
  /**
   * Visible title for the group; renders as a `legend`. Omit for a radio group
   * without a visible fieldset title.
   */
  legend?: string;
  /** Renders under the legend as supportive copy. */
  hint?: string;
  /**
   * Stack in one column, or a responsive multi-column **grid** for equally sized cards.
   * @default "stack"
   */
  layout?: "stack" | "grid";
};

/**
 * Wraps Radix `RadioGroup` in a `fieldset` with optional legend. Place
 * {@link SelectChoiceCard} children (each with a `RadioGroupItem` value) as direct
 * children so selection stays in one group.
 */
export function SelectChoiceCardGroup({
  className,
  legend,
  hint,
  layout = "stack",
  children,
  ...radioProps
}: SelectChoiceCardGroupProps) {
  return (
    <FieldSet className="w-full min-w-0">
      {legend ? (
        <div className="mb-3 space-y-1">
          <FieldLegend className="text-sm font-semibold text-foreground">{legend}</FieldLegend>
          {hint ? (
            <p className="text-sm text-muted-foreground" id={hint ? undefined : undefined}>
              {hint}
            </p>
          ) : null}
        </div>
      ) : null}
      <RadioGroup
        className={cn(
          "w-full gap-3 p-0",
          layout === "grid" && "grid grid-cols-1 gap-3 @md/field:grid-cols-2 @xl/field:grid-cols-3",
          layout === "stack" && "flex flex-col",
          className,
        )}
        {...radioProps}
      >
        {children}
      </RadioGroup>
    </FieldSet>
  );
}

