  return (
    <div className={cn("w-full min-w-0", className)}>
      <SelectChoiceCardGroup
        className="gap-3 p-0"
        legend={legend}
        hint={hint}
        layout={layout}
        name={name}
        value={value ?? ""}
        onValueChange={(v) => {
          if (CERTIFICATION_INTENT_IDS.includes(v as CertificationIntentId)) {
            onValueChange(v as CertificationIntentId);
