      >
        {options.map((opt) => (
          <SelectChoiceCard
            key={opt.id}
            value={opt.id}
            radioId={`${base}-${opt.id}`}
            title={opt.title}
            description={opt.description}
            leading={opt.leading}
            emphasis={opt.emphasis}
            disabled={opt.disabled}
          />
        ))}
      </SelectChoiceCardGroup>
    </div>
  );
}

