import type { Meta, StoryObj } from "@storybook/react-vite";
import { useState } from "react";

import { RadioGroup } from "@procertus-ui/ui";

import { SelectChoiceCard } from "./SelectChoiceCard";
import { SelectChoiceCardGroup } from "./SelectChoiceCardGroup";

const meta = {
  title: "ui-lib/SelectChoiceCard",
  parameters: {
    layout: "centered",
    docs: {
      description: {
        component:
          "One option inside a `RadioGroup`: **single selection** with `emphasis` to separate a primary product path, secondary (e.g. ATG), and tertiary (e.g. innovation) routes. Pairs with `SelectChoiceCardGroup` for a fieldset + legend. Pure presentation: parent owns `value` and `onValueChange`.",
      },
    },
  },
  tags: ["autodocs"],
} satisfies Meta<typeof SelectChoiceCard>;

export default meta;

const emphases = ["primary", "secondary", "tertiary"] as const;

function AllEmphases() {
  const [v, setV] = useState("primary-option");
  return (
    <RadioGroup value={v} onValueChange={setV} className="flex w-full max-w-md flex-col gap-3">
      {emphases.map((e) => (
        <SelectChoiceCard
          key={e}
          value={`${e}-option`}
          radioId={`sc-${e}`}
          title={`${e[0]!.toUpperCase()}${e.slice(1)} path`}
          description="Optional description that scales with the emphasis level."
          emphasis={e}
        />
      ))}
    </RadioGroup>
  );
}

export const Emphases = {
  render: () => <AllEmphases />,
} as unknown as StoryObj<typeof meta>;

function WithFieldset() {
  const [v, setV] = useState("");
  return (
    <div className="w-full min-w-0 max-w-2xl">
      <SelectChoiceCardGroup
        layout="grid"
        legend="Pick one"
        hint="Tertiary options are visually lighter for de-emphasized routes."
        value={v}
        onValueChange={setV}
      >
        <SelectChoiceCard
          value="a"
          radioId="fs-a"
          title="Primary (product certification)"
