/**
 * Multi-select of product / product-type rows. Each check adds a line your parent maps to a
 * **draft** certification request. Presentational: parent controls `selectedIds` and
 * `onChange`.
 */
import { useId } from "react";

import { cn } from "@/lib/utils";
import {
  Checkbox,
  Field,
  FieldContent,
  FieldGroup,
  FieldLabel,
  FieldSet,
} from "@procertus-ui/ui";

export type ProductMultiSelectOption = {
  id: string;
  label: string;
  description?: string;
  disabled?: boolean;
};

export type ProductMultiSelectProps = {
  className?: string;
  /** Ids the user has checked. */
  selectedIds: readonly string[];
  onChange: (ids: string[]) => void;
  options: ProductMultiSelectOption[];
  /** Fieldset / group heading. */
  legend: string;
  description?: string;
  /** Renders when `options` is empty. */
  emptyMessage?: string;
  /** Optional name for native form / testing. */
  name?: string;
};

function toggleIn(ids: readonly string[], id: string, on: boolean): string[] {
  if (on) {
    if (ids.includes(id)) {
      return [...ids];
    }
    return [...ids, id];
  }
  return ids.filter((x) => x !== id);
}

export function ProductMultiSelect({
  className,
  selectedIds,
  onChange,
  options,
  legend,
  description,
  emptyMessage = "No options to select.",
  name: nameProp,
}: ProductMultiSelectProps) {
  const set = new Set(selectedIds);
  const base = useId();
  const name = nameProp ?? `pms-${base}`;

  return (
    <FieldSet className={cn("w-full min-w-0", className)}>
      <div className="mb-2 space-y-0.5">
        <div className="text-base font-semibold">{legend}</div>
        {description ? <p className="text-sm text-muted-foreground">{description}</p> : null}
      </div>
      {options.length === 0 ? (
        <p className="rounded-md border border-dashed border-border/60 px-3 py-4 text-sm text-muted-foreground">{emptyMessage}</p>
      ) : (
        <FieldGroup className="max-h-[min(50vh,28rem)] space-y-0 overflow-y-auto rounded-md border border-border/50 p-1">
          {options.map((opt) => {
            const cbId = `${name}-${opt.id}`;
            const checked = set.has(opt.id);
            return (
              <Field
                key={opt.id}
                className="rounded-sm px-2 py-1.5 transition hover:bg-muted/20"
                data-disabled={opt.disabled ? "true" : undefined}
                orientation="horizontal"
              >
                <Checkbox
                  name={name}
                  id={cbId}
                  checked={checked}
                  onCheckedChange={(c) => {
                    if (opt.disabled) {
                      return;
                    }
                    onChange(toggleIn(selectedIds, opt.id, c === true));
                  }}
                  disabled={opt.disabled}
                />
                <FieldContent>
                  <FieldLabel htmlFor={cbId} className="!block text-left font-medium">
                    {opt.label}
                    {opt.description ? (
                      <span className="mt-0.5 block text-sm font-normal text-muted-foreground">{opt.description}</span>
                    ) : null}
                  </FieldLabel>
                </FieldContent>
              </Field>
            );
          })}
        </FieldGroup>
      )}
    </FieldSet>
  );
}

/**
 * **Props-only** certification / procedure chips. Parent normalizes domain data (e.g. CE,
 * BENOR, ATG, SSD) into these items — this component does not read the decision JSON.
 * Use `presentation: "chip"` for certifiable values, `muted` for low emphasis, and
 * `not-offered` for empty / not-by-us / “(x)” style lines (copy is still parent-driven).
 */
import type { ReactNode } from "react";

import { cn } from "@/lib/utils";
import { Badge } from "@procertus-ui/ui";

export type CertificationBadgePresentation = "chip" | "muted" | "not-offered";

export type CertificationBadgeItem = {
  id: string;
  shortLabel: string;
  presentation: CertificationBadgePresentation;
  /**
   * Chip text or a legible “not available” / symbol explanation for `not-offered`.
   */
  text?: string;
  /** When `not-offered`, optional extra line (e.g. procedure cell). */
  subline?: string;
};

export type CertificationBadgeRowProps = {
  className?: string;
  items: CertificationBadgeItem[];
  /** Renders when `items` is empty. */
  emptyMessage?: string;
  /** Start slot: e.g. a “Certification” label. */
  leading?: ReactNode;
};

const chipClass: Record<CertificationBadgePresentation, string> = {
  chip: "font-normal",
  muted: "border-border/50 bg-muted/30 font-normal text-muted-foreground",
  "not-offered": "border-dashed border-muted-foreground/30 bg-transparent font-normal text-muted-foreground",
};

export function CertificationBadgeRow({
  className,
  items,
  emptyMessage = "No certification information.",
  leading,
}: CertificationBadgeRowProps) {
  if (items.length === 0) {
    return (
      <div className={cn("text-sm text-muted-foreground", className)} role="status">
        {emptyMessage}
      </div>
    );
  }
  return (
    <div className={cn("flex flex-col gap-2", className)}>
      {leading ? <div className="text-xs font-medium text-muted-foreground uppercase tracking-wider">{leading}</div> : null}
      <div className="flex flex-wrap gap-1.5">
        {items.map((it) => {
          if (it.presentation === "not-offered" || it.presentation === "muted") {
            return (
              <div
                key={it.id}
                className="inline-flex min-w-0 max-w-full flex-col gap-0.5 rounded-md border px-2 py-1 text-left text-xs leading-snug"
                data-presentation={it.presentation}
              >
                <span className="font-medium text-foreground">{it.shortLabel}</span>
                {it.text ? (
                  <span className={it.presentation === "not-offered" ? "text-muted-foreground" : "text-muted-foreground/90"}>
                    {it.text}
                  </span>
                ) : null}
                {it.subline ? <span className="text-[11px] text-muted-foreground">{it.subline}</span> : null}
              </div>
            );
          }
          return (
            <Badge key={it.id} variant="secondary" className={cn("max-w-full", chipClass[it.presentation])} title={it.subline}>
              <span className="font-medium">{it.shortLabel}</span>
              {it.text ? <span className="ml-1 font-normal opacity-90">: {it.text}</span> : null}
            </Badge>
          );
        })}
      </div>
    </div>
  );
}

/**
 * Draft certification requests in the session: **edit** and **remove** are callbacks
 * only — no navigation. Use with `ProductMultiSelect` output (one draft per selected
 * product type) or similar parent state.
 */
import { Delete02Icon, PencilEdit02Icon } from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";
import type { ReactNode } from "react";

import { cn } from "@/lib/utils";
import { Button, Card, CardContent, CardDescription, CardHeader, CardTitle, Empty, EmptyDescription, EmptyIcon, EmptyTitle, Separator } from "@procertus-ui/ui";

export type DraftRequestItem = {
  id: string;
  title: string;
  subtitle?: string;
  /** Free slot (e.g. a `CertificationBadgeRow` preview). */
  details?: ReactNode;
};

export type DraftRequestListProps = {
  className?: string;
  title: string;
  description?: string;
  drafts: DraftRequestItem[];
  onEdit: (id: string) => void;
  onRemove: (id: string) => void;
  /** Optional string override for the empty `Empty` block. */
  emptyTitle?: string;
  emptyDescription?: string;
  /** Edit / remove button labels. */
  editLabel?: string;
  removeLabel?: string;
};

export function DraftRequestList({
  className,
  title,
  description,
  drafts,
  onEdit,
  onRemove,
  emptyTitle = "No draft requests yet",
  emptyDescription = "Add product types from the previous step, or return to the drilldown to add more.",
  editLabel = "Edit",
  removeLabel = "Remove",
}: DraftRequestListProps) {
  return (
    <Card className={cn("w-full max-w-3xl overflow-hidden", className)}>
      <CardHeader>
        <CardTitle>{title}</CardTitle>
        {description ? <CardDescription>{description}</CardDescription> : null}
      </CardHeader>
      <CardContent>
        {drafts.length === 0 ? (
          <Empty>
            <EmptyIcon />
            <EmptyTitle>{emptyTitle}</EmptyTitle>
            <EmptyDescription>{emptyDescription}</EmptyDescription>
          </Empty>
        ) : (
          <ul className="flex flex-col gap-0" role="list">
            {drafts.map((d, i) => (
              <li key={d.id} className="min-w-0">
                {i > 0 ? <Separator className="my-1" /> : null}
                <div className="flex flex-col gap-2 py-2 sm:flex-row sm:items-start sm:justify-between sm:gap-4">
                  <div className="min-w-0 flex-1">
                    <p className="font-medium text-foreground">{d.title}</p>
                    {d.subtitle ? <p className="text-sm text-muted-foreground">{d.subtitle}</p> : null}
                    {d.details ? <div className="mt-2 min-w-0">{d.details}</div> : null}
                  </div>
                  <div className="flex shrink-0 flex-wrap justify-end gap-2">
                    <Button type="button" size="sm" variant="outline" onClick={() => onEdit(d.id)} aria-label={`${editLabel}: ${d.title}`}>
                      <HugeiconsIcon icon={PencilEdit02Icon} className="size-4" strokeWidth={1.5} />
                      {editLabel}
                    </Button>
                    <Button
                      type="button"
                      size="sm"
                      variant="secondary"
                      onClick={() => onRemove(d.id)}
                      className="text-destructive-foreground hover:text-destructive-foreground"
                      aria-label={`${removeLabel}: ${d.title}`}
                    >
                      <HugeiconsIcon icon={Delete02Icon} className="size-4" strokeWidth={1.5} />
                      {removeLabel}
                    </Button>
                  </div>
                </div>
              </li>
            ))}
          </ul>
        )}
      </CardContent>
    </Card>
  );
}

/**
