import { useCallback, useMemo, useState } from "react";

export type ChoiceSelectionMode = "single" | "multiple";

export type UseChoiceSelectionOptions =
  | {
      mode: "single";
      /** Initially selected option id */
      defaultSelectedId?: string;
    }
  | {
      mode: "multiple";
      defaultSelectedIds?: readonly string[];
    };

export type UseChoiceSelectionResult = {
  mode: ChoiceSelectionMode;
  /** All selected ids (length 0 or 1 when `mode === "single"`). */
  selectedIds: string[];
  /** Convenience when `mode === "single"` — first selected id or `undefined`. */
  selectedId: string | undefined;
  /** Toggle one id (single replaces; multiple XORs membership). */
  toggle: (id: string) => void;
  /** Replace the full selection (clamped to one id when single). */
  setSelectedIds: (ids: readonly string[]) => void;
  setSelectedId: (id: string | undefined) => void;
  isSelected: (id: string) => boolean;
  clear: () => void;
};

function normalizeSingleIds(ids: readonly string[]): string[] {
  if (ids.length <= 1) {
    return [...ids];
  }
  return ids[0] !== undefined ? [ids[0]] : [];
}

export function useChoiceSelection(options: UseChoiceSelectionOptions): UseChoiceSelectionResult {
  const mode = options.mode;

  const [selectedIds, setSelectedIdsState] = useState<string[]>(() => {
    if (options.mode === "single") {
      const id = options.defaultSelectedId;
      return id ? [id] : [];
    }
    return [...(options.defaultSelectedIds ?? [])];
  });

  const setSelectedIds = useCallback(
    (ids: readonly string[]) => {
      setSelectedIdsState(mode === "single" ? normalizeSingleIds(ids) : [...ids]);
    },
    [mode],
  );

  const setSelectedId = useCallback(
    (id: string | undefined) => {
      setSelectedIdsState(id ? [id] : []);
    },
    [],
  );

  const toggle = useCallback(
    (id: string) => {
      setSelectedIdsState((prev) => {
        if (mode === "single") {
          return prev[0] === id ? [] : [id];
        }
        return prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id];
      });
    },
    [mode],
  );

  const isSelected = useCallback(
    (id: string) => selectedIds.includes(id),
    [selectedIds],
  );

  const clear = useCallback(() => setSelectedIdsState([]), []);

  const selectedId = useMemo(
    () => (mode === "single" ? selectedIds[0] : undefined),
    [mode, selectedIds],
  );

  return useMemo(
    () => ({
      mode,
      selectedIds,
      selectedId,
      toggle,
      setSelectedIds,
      setSelectedId,
      isSelected,
      clear,
    }),
    [mode, selectedIds, selectedId, toggle, setSelectedIds, setSelectedId, isSelected, clear],
  );
}

import { useCallback, useMemo, useState } from "react";

export type ChoiceSelectionMode = "single" | "multiple";

export type UseChoiceSelectionOptions =
  | {
      mode: "single";
      defaultSelectedId?: string;
    }
  | {
      mode: "multiple";
      defaultSelectedIds?: readonly string[];
    };

export type UseChoiceSelectionResult = {
  mode: ChoiceSelectionMode;
  selectedIds: string[];
  selectedId: string | undefined;
  toggle: (id: string) => void;
  setSelectedIds: (ids: readonly string[]) => void;
  setSelectedId: (id: string | undefined) => void;
  isSelected: (id: string) => boolean;
  clear: () => void;
};

function clampSingle(ids: readonly string[]): string[] {
  if (ids.length <= 1) {
    return [...ids];
  }
  const first = ids[0];
  return first !== undefined ? [first] : [];
}

export function useChoiceSelection(options: UseChoiceSelectionOptions): UseChoiceSelectionResult {
  const mode = options.mode;

  const [selectedIds, setSelectedIdsState] = useState<string[]>(() => {
    if (options.mode === "single") {
      const id = options.defaultSelectedId;
      return id ? [id] : [];
    }
    return [...(options.defaultSelectedIds ?? [])];
  });

  const setSelectedIds = useCallback(
    (ids: readonly string[]) => {
      setSelectedIdsState(mode === "single" ? clampSingle(ids) : [...ids]);
    },
    [mode],
  );

  const setSelectedId = useCallback((id: string | undefined) => {
    setSelectedIdsState(id ? [id] : []);
  }, []);

  const toggle = useCallback(
    (id: string) => {
      setSelectedIdsState((prev) => {
        if (mode === "single") {
          return prev[0] === id ? [] : [id];
        }
        return prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id];
      });
    },
    [mode],
  );

  const isSelected = useCallback((id: string) => selectedIds.includes(id), [selectedIds]);

  const clear = useCallback(() => setSelectedIdsState([]), []);

  const selectedId = mode === "single" ? selectedIds[0] : undefined;

  return useMemo(
    (): UseChoiceSelectionResult => ({
      mode,
      selectedIds,
      selectedId,
      toggle,
      setSelectedIds,
      setSelectedId,
      isSelected,
      clear,
    }),
    [mode, selectedIds, selectedId, toggle, setSelectedIds, setSelectedId, isSelected, clear],
  );
}

