export type SelectChoiceEmphasis = NonNullable<VariantProps<typeof shellVariants>["emphasis"]>;
export type SelectChoiceSelectionMode = "single" | "multiple";

export type SelectChoiceCardProps = {
  className?: string;
  /** Option id — `RadioGroupItem` value (single) or stable key for toggling (multiple). */
  value: string;
  /** Stable id for native control + label (`htmlFor`). */
  controlId: string;
  title: ReactNode;
  description?: ReactNode;
  /**
   * Inline icon for **default** layout (start column). Ignored when `appearance="hero"` and `icon` is set.
   */
  leading?: ReactNode;
  /**
   * Prominent centered icon (Empty-style circular well), **hero** layout.
   */
  icon?: ReactNode;
  /** @default "primary" */
  emphasis?: SelectChoiceEmphasis;
  /** @default "default" — `hero` uses larger centered type and padding (empty-state outline). */
  appearance?: SelectChoiceAppearance;
  /** @default "single" — use with `RadioGroup`; `multiple` uses `Checkbox` + `checked` props. */
  selectionMode?: SelectChoiceSelectionMode;
  disabled?: boolean;
  /** Multiple mode — controlled checked state */
  checked?: boolean;
  /** Multiple mode — toggle handler */
  onCheckedChange?: (checked: boolean) => void;
};

export function SelectChoiceCard({
  className,
  value,
  controlId,
  title,
  description,
  leading,
  icon,
  emphasis = "primary",
  appearance = "default",
  selectionMode = "single",
  disabled = false,
  checked,
  onCheckedChange,
}: SelectChoiceCardProps) {
  const isHero = appearance === "hero";
  const isMultiple = selectionMode === "multiple";

  const controlClass = cn(
    isHero && "sr-only",
    !isHero && !isMultiple && "mt-1.5",
    !isHero && isMultiple && "mt-1",
  );

  const control =
    isMultiple ? (
      <Checkbox
        id={controlId}
        checked={checked}
        onCheckedChange={(s) => onCheckedChange?.(s === true)}
        disabled={disabled}
        className={controlClass}
      />
    ) : (
      <RadioGroupItem value={value} id={controlId} disabled={disabled} className={controlClass} />
    );

  const showHeroIcon = isHero && icon !== undefined && icon !== null;
  const showLeading = !isHero && leading;

  return (
    <FieldLabel className={cn(shellVariants({ appearance, emphasis }), className)}>
      <Field
        data-choice-appearance={appearance}
        data-choice-emphasis={emphasis}
        orientation={isHero ? "vertical" : "horizontal"}
        className={cn(
          "items-stretch *:data-[slot=field-content]:min-w-0",
          isHero && "items-center justify-center text-center",
          !isHero && "items-stretch",
        )}
        data-disabled={disabled ? "true" : undefined}
      >
        {control}
        <FieldContent
          className={cn(
            showLeading && "flex min-w-0 flex-row items-start gap-3",
            isHero && "flex w-full flex-col items-center gap-section text-center",
          )}
        >
          {showHeroIcon ? (
            <EmptyIcon className="shrink-0 [&>svg]:size-7">{icon}</EmptyIcon>
          ) : null}
          {showLeading ? (
            <div className="shrink-0 self-start pt-0.5 text-muted-foreground [&_svg]:size-5">{leading}</div>
          ) : null}
          <div className={cn("min-w-0", !isHero && "flex-1", isHero && "flex flex-col items-center gap-2")}>
            <FieldTitle
              className={cn(
                titleVariants({ appearance, emphasis }),
                isHero ? "justify-center text-center" : "",
              )}
            >
              <Label
                htmlFor={controlId}
                className={cn(
                  !isHero && emphasis === "tertiary" && "text-muted-foreground",
                  !isHero && "text-left leading-snug",
                  isHero && "block text-center",
                )}
              >
                {title}
              </Label>
            </FieldTitle>
            {description ? (
              <FieldDescription className={cn(!isHero && "mt-1.5", isHero && "mt-0", descVariants({ appearance, emphasis }))}>
                {description}
              </FieldDescription>
            ) : null}
          </div>
        </FieldContent>
      </Field>
    </FieldLabel>
  );
}

import type { ComponentProps, ReactNode } from "react";

import { cn } from "@/lib/utils";
import { FieldLegend, FieldSet, RadioGroup } from "@procertus-ui/ui";

import type { ChoiceSelectionMode } from "./useChoiceSelection";

export type SelectChoiceCardGroupProps = Omit<ComponentProps<typeof RadioGroup>, "children"> & {
  className?: string;
  children: ReactNode;
  /**
   * Visible group title; renders a `legend` as the first child of the fieldset.
   */
  legend?: string;
  /** Renders as supportive copy under the legend. */
  hint?: string;
  /**
   * `stack` — one column. `grid` — responsive multi-column for equal card widths.
   * @default "stack"
   */
  layout?: "stack" | "grid";
  /**
   * **single** — inner `RadioGroup` (one value). **multiple** — `role="group"` div; pair each
   * {@link SelectChoiceCard} with `selectionMode="multiple"` and `checked` / `onCheckedChange`.
   * When `multiple`, `value` / `onValueChange` / `defaultValue` on this component are ignored.
   * @default "single"
   */
  selectionMode?: ChoiceSelectionMode;
};

const layoutClass = (layout: "stack" | "grid") =>
  cn(
    "w-full gap-3 p-0",
    layout === "grid" && "grid grid-cols-1 gap-3 md:grid-cols-2 xl:grid-cols-3",
    layout === "stack" && "flex flex-col",
  );

/**
 * `fieldset` + either a `RadioGroup` (single) or a grouping `div` (multiple).
 */
export function SelectChoiceCardGroup({
  className,
  legend,
  hint,
  layout = "stack",
  selectionMode = "single",
  children,
  ...radioRest
}: SelectChoiceCardGroupProps) {
  return (
    <FieldSet className="w-full min-w-0">
      {legend ? <FieldLegend className="text-base font-semibold">{legend}</FieldLegend> : null}
      {hint ? <p className="mb-3 text-sm text-muted-foreground">{hint}</p> : null}
      {selectionMode === "multiple" ? (
        <div role="group" className={cn(layoutClass(layout), className)}>
          {children}
        </div>
      ) : (
        <RadioGroup className={cn(layoutClass(layout), className)} {...radioRest}>
          {children}
        </RadioGroup>
      )}
    </FieldSet>
  );
}

